import { useState, useRef, useEffect } from "react";


const SUGGESTED_PROMPTS = [
  "I feel like I'm never enough no matter how hard I try",
  "I keep failing at something I promised myself I'd stop doing",
  "I'm struggling to forgive someone who hurt me",
  "I feel far from God and I don't know why",
  "What does Mockingbird believe about grace?",
];

// Mockingbird logo — illustrated bird on branch, ringed circle frame
const LOGO_DATA_URI = "data:image/png;base64,";

function MbirdLogo({ size = 40 }) {
  return (
    <img
      src={LOGO_DATA_URI}
      alt="Mockingbot"
      width={size}
      height={size}
      style={{ display: "block", borderRadius: "50%", objectFit: "cover" }}
    />
  );
}

function parseMessageWithLinks(text) {
  const parts = text.split(/\n---\n/);
  const mainText = parts[0];
  const resourcesText = parts[1] || "";
  const resourceLines = resourcesText.split("\n").filter(l => l.trim().startsWith("-"));
  const resources = resourceLines.map(line => {
    const linkMatch = /\[([^\]]+)\]\((https?:\/\/[^\)]+)\)/.exec(line);
    const sourceMatch = / — (.+)$/.exec(line);
    if (linkMatch) {
      return { label: linkMatch[1], url: linkMatch[2], source: sourceMatch ? sourceMatch[1].trim() : "" };
    }
    return null;
  }).filter(Boolean);
  return { mainText, resources };
}

function getSourceIcon(url) {
  if (url.includes("biblegateway")) return "📖";
  if (url.includes("mbird")) return "🐦";
  if (url.includes("fireside") || url.includes("spotify")) return "🎙️";
  return "🔗";
}

function getSourceAccent(url) {
  if (url.includes("biblegateway")) return "#6a9e72";
  if (url.includes("mbird")) return "#E8614A";
  if (url.includes("fireside")) return "#8a6fb5";
  return "#999";
}

export default function Mockingbot() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [started, setStarted] = useState(false);
  const bottomRef = useRef(null);
  const textareaRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  const sendMessage = async (text) => {
    const userText = text || input.trim();
    if (!userText || loading) return;
    setStarted(true);
    setInput("");
    if (textareaRef.current) textareaRef.current.style.height = "auto";
    const newMessages = [...messages, { role: "user", content: userText }];
    setMessages(newMessages);
    setLoading(true);
    try {
      const response = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ messages: newMessages }),
      });
      const data = await response.json();
      if (!response.ok) {
        const msg = data?.error?.message || data?.error || "Something went wrong talking to the server.";
        setMessages([...newMessages, { role: "assistant", content: `⚠️ ${msg}` }]);
        return;
      }
      const textBlocks = data.content?.filter(b => b.type === "text") || [];
      const reply = textBlocks.map(b => b.text).join("\n") || "Something went wrong. Please try again.";
      setMessages([...newMessages, { role: "assistant", content: reply }]);
    } catch {
      setMessages([...newMessages, { role: "assistant", content: "⚠️ Couldn't reach the server. Check your connection and try again." }]);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); }
  };

  const handleTextareaInput = (e) => {
    setInput(e.target.value);
    const ta = textareaRef.current;
    if (ta) { ta.style.height = "auto"; ta.style.height = Math.min(ta.scrollHeight, 140) + "px"; }
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "#ffffff",
      color: "#1a1a1a",
      fontFamily: "'Georgia', 'Times New Roman', serif",
      display: "flex",
      flexDirection: "column",
    }}>
      {/* Header */}
      <header style={{
        borderBottom: "1px solid #ebebeb",
        padding: "16px 24px",
        display: "flex",
        alignItems: "center",
        gap: "12px",
        background: "#ffffff",
        position: "sticky",
        top: 0,
        zIndex: 10,
      }}>
        <MbirdLogo size={42} />
        <div>
          <div style={{ fontSize: 18, fontWeight: "bold", letterSpacing: "0.02em", color: "#1a1a1a" }}>
            Mockingbot
          </div>
          <div style={{ fontSize: 12, color: "#999", fontFamily: "sans-serif", fontStyle: "italic" }}>
            grace-centered conversation
          </div>
        </div>
        <div style={{ marginLeft: "auto", fontSize: 11, color: "#ccc", fontFamily: "sans-serif", textAlign: "right" }}>
          powered by<br />
          <span style={{ color: "#E8614A" }}>Mockingbird Ministries</span>
        </div>
      </header>

      {/* Main */}
      <main style={{
        flex: 1,
        display: "flex",
        flexDirection: "column",
        maxWidth: 720,
        width: "100%",
        margin: "0 auto",
        padding: "0 16px",
      }}>
        {!started && (
          <div style={{
            flex: 1,
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            justifyContent: "center",
            padding: "60px 0 40px",
            textAlign: "center",
          }}>
            <MbirdLogo size={72} />
            <div style={{ height: 28 }} />
            <div style={{ fontSize: 12, color: "#bbb", fontFamily: "sans-serif", letterSpacing: "0.14em", textTransform: "uppercase", marginBottom: 16 }}>
              Mockingbird Ministries
            </div>
            <h1 style={{
              fontSize: "clamp(26px, 5vw, 40px)",
              fontWeight: "normal",
              lineHeight: 1.25,
              color: "#1a1a1a",
              marginBottom: 14,
              maxWidth: 500,
            }}>
              What's weighing on you right now?
            </h1>
            <p style={{
              fontSize: 16,
              color: "#999",
              lineHeight: 1.7,
              maxWidth: 420,
              marginBottom: 48,
              fontStyle: "italic",
            }}>
              Grace finds you where you are — not where you think you should be.
            </p>
            <div style={{ display: "flex", flexDirection: "column", gap: 10, width: "100%", maxWidth: 500 }}>
              {SUGGESTED_PROMPTS.map((p, i) => (
                <button key={i} onClick={() => sendMessage(p)} style={{
                  background: "transparent",
                  border: "1px solid #e8e8e8",
                  borderRadius: 8,
                  padding: "12px 18px",
                  color: "#777",
                  fontFamily: "Georgia, serif",
                  fontSize: 14,
                  cursor: "pointer",
                  textAlign: "left",
                  lineHeight: 1.4,
                  transition: "all 0.15s",
                }}
                  onMouseEnter={e => {
                    e.currentTarget.style.borderColor = "#E8614A";
                    e.currentTarget.style.color = "#1a1a1a";
                    e.currentTarget.style.background = "#fff8f7";
                  }}
                  onMouseLeave={e => {
                    e.currentTarget.style.borderColor = "#e8e8e8";
                    e.currentTarget.style.color = "#777";
                    e.currentTarget.style.background = "transparent";
                  }}
                >
                  "{p}"
                </button>
              ))}
            </div>
          </div>
        )}

        {started && (
          <div style={{ paddingTop: 32, paddingBottom: 24, display: "flex", flexDirection: "column", gap: 32 }}>
            {messages.map((msg, i) => {
              if (msg.role === "user") {
                return (
                  <div key={i} style={{ display: "flex", justifyContent: "flex-end" }}>
                    <div style={{
                      background: "#fff8f7",
                      border: "1px solid #f0d8d4",
                      borderRadius: "16px 16px 4px 16px",
                      padding: "13px 18px",
                      maxWidth: "78%",
                      fontSize: 15,
                      lineHeight: 1.65,
                      color: "#333",
                      fontStyle: "italic",
                    }}>
                      {msg.content}
                    </div>
                  </div>
                );
              }

              const { mainText, resources } = parseMessageWithLinks(msg.content);
              return (
                <div key={i} style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
                  <div style={{ flexShrink: 0, marginTop: 2 }}>
                    <MbirdLogo size={30} />
                  </div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 15, lineHeight: 1.85, color: "#2a2a2a" }}>
                      {mainText.split("\n").map((para, j) =>
                        para.trim() ? <p key={j} style={{ margin: "0 0 14px" }}>{para}</p> : null
                      )}
                    </div>
                    {resources.length > 0 && (
                      <div style={{ marginTop: 20, borderTop: "1px solid #f0f0f0", paddingTop: 16 }}>
                        <div style={{
                          fontSize: 10,
                          color: "#bbb",
                          fontFamily: "sans-serif",
                          letterSpacing: "0.12em",
                          textTransform: "uppercase",
                          marginBottom: 10,
                        }}>
                          Further reading
                        </div>
                        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                          {resources.map((r, j) => (
                            <a key={j} href={r.url} target="_blank" rel="noopener noreferrer"
                              style={{
                                display: "flex",
                                alignItems: "center",
                                gap: 10,
                                padding: "10px 14px",
                                background: "#fafafa",
                                border: "1px solid #ebebeb",
                                borderLeft: `3px solid ${getSourceAccent(r.url)}`,
                                borderRadius: "0 8px 8px 0",
                                textDecoration: "none",
                                transition: "all 0.15s",
                              }}
                              onMouseEnter={e => {
                                e.currentTarget.style.background = "#fff8f7";
                                e.currentTarget.style.borderColor = "#f0d8d4";
                              }}
                              onMouseLeave={e => {
                                e.currentTarget.style.background = "#fafafa";
                                e.currentTarget.style.borderColor = "#ebebeb";
                              }}
                            >
                              <span style={{ fontSize: 15 }}>{getSourceIcon(r.url)}</span>
                              <div style={{ flex: 1, minWidth: 0 }}>
                                <div style={{
                                  fontSize: 13,
                                  color: "#333",
                                  fontFamily: "Georgia, serif",
                                  whiteSpace: "nowrap",
                                  overflow: "hidden",
                                  textOverflow: "ellipsis",
                                }}>
                                  {r.label}
                                </div>
                                {r.source && (
                                  <div style={{ fontSize: 11, color: "#aaa", fontFamily: "sans-serif", marginTop: 2 }}>
                                    {r.source}
                                  </div>
                                )}
                              </div>
                              <span style={{ fontSize: 12, color: "#ccc" }}>↗</span>
                            </a>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              );
            })}

            {loading && (
              <div style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
                <div style={{ flexShrink: 0, position: "relative" }}>
                  <div className="mbird-chirp"><MbirdLogo size={30} /></div>
                  <span className="chirp-note chirp-note-1">♪</span>
                  <span className="chirp-note chirp-note-2">♫</span>
                  <span className="chirp-note chirp-note-3">♪</span>
                </div>
                <div style={{ display: "flex", gap: 5, alignItems: "center", paddingTop: 8 }}>
                  {[0, 1, 2].map(d => (
                    <div key={d} style={{
                      width: 7, height: 7,
                      borderRadius: "50%",
                      background: "#E8614A",
                      animation: "pulse 1.2s ease-in-out infinite",
                      animationDelay: `${d * 0.2}s`,
                    }} />
                  ))}
                </div>
              </div>
            )}
            <div ref={bottomRef} />
          </div>
        )}
      </main>

      {/* Input */}
      <div style={{
        borderTop: "1px solid #ebebeb",
        background: "#ffffff",
        padding: "16px",
        position: "sticky",
        bottom: 0,
      }}>
        <div style={{ maxWidth: 720, margin: "0 auto", display: "flex", gap: 10, alignItems: "flex-end" }}>
          <textarea
            ref={textareaRef}
            value={input}
            onChange={handleTextareaInput}
            onKeyDown={handleKeyDown}
            placeholder="Say what's on your mind..."
            rows={1}
            style={{
              flex: 1,
              background: "#fafafa",
              border: "1px solid #e8e8e8",
              borderRadius: 12,
              padding: "13px 16px",
              color: "#1a1a1a",
              fontFamily: "Georgia, serif",
              fontSize: 15,
              lineHeight: 1.5,
              resize: "none",
              outline: "none",
              overflowY: "auto",
              minHeight: 48,
              maxHeight: 140,
            }}
            onFocus={e => e.target.style.borderColor = "#E8614A"}
            onBlur={e => e.target.style.borderColor = "#e8e8e8"}
          />
          <button
            onClick={() => sendMessage()}
            disabled={!input.trim() || loading}
            style={{
              width: 46, height: 46,
              borderRadius: 12,
              background: input.trim() && !loading ? "#E8614A" : "#f0f0f0",
              border: "none",
              cursor: input.trim() && !loading ? "pointer" : "default",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 18,
              color: input.trim() && !loading ? "#fff" : "#ccc",
              flexShrink: 0,
              transition: "all 0.15s",
            }}
          >↑</button>
        </div>
        <div style={{
          maxWidth: 720,
          margin: "10px auto 0",
          textAlign: "center",
          fontSize: 11,
          color: "#ccc",
          fontFamily: "sans-serif",
        }}>
          Mockingbot reflects Mockingbird Ministries theology — not a substitute for pastoral care
        </div>
      </div>

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 0.25; transform: scale(0.8); }
          50% { opacity: 1; transform: scale(1); }
        }
        @keyframes chirpBounce {
          0%, 100% { transform: translateY(0) rotate(0deg); }
          15% { transform: translateY(-3px) rotate(-4deg); }
          30% { transform: translateY(0) rotate(0deg); }
          45% { transform: translateY(-2px) rotate(3deg); }
          60% { transform: translateY(0) rotate(0deg); }
        }
        @keyframes noteFloat1 {
          0% { opacity: 0; transform: translate(0, 0) scale(0.5) rotate(-10deg); }
          15% { opacity: 1; transform: translate(4px, -4px) scale(0.9) rotate(0deg); }
          70% { opacity: 0.9; transform: translate(14px, -20px) scale(1) rotate(8deg); }
          100% { opacity: 0; transform: translate(18px, -28px) scale(0.8) rotate(12deg); }
        }
        @keyframes noteFloat2 {
          0% { opacity: 0; transform: translate(0, 0) scale(0.5) rotate(8deg); }
          25% { opacity: 0; }
          40% { opacity: 1; transform: translate(6px, -6px) scale(0.9) rotate(0deg); }
          85% { opacity: 0.9; transform: translate(18px, -24px) scale(1) rotate(-10deg); }
          100% { opacity: 0; transform: translate(22px, -32px) scale(0.8) rotate(-14deg); }
        }
        .mbird-chirp {
          display: inline-block;
          animation: chirpBounce 0.9s ease-in-out infinite;
          transform-origin: 70% 80%;
        }
        .chirp-note {
          position: absolute;
          top: 2px;
          right: -6px;
          font-size: 11px;
          color: #E8614A;
          font-weight: bold;
          pointer-events: none;
          opacity: 0;
        }
        .chirp-note-1 { animation: noteFloat1 1.8s ease-out infinite; animation-delay: 0s; }
        .chirp-note-2 { animation: noteFloat2 1.8s ease-out infinite; animation-delay: 0.5s; font-size: 9px; top: -2px; }
        .chirp-note-3 { animation: noteFloat1 1.8s ease-out infinite; animation-delay: 1s; font-size: 10px; top: 4px; }
        * { box-sizing: border-box; }
        textarea::placeholder { color: #bbb; }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #e8e8e8; border-radius: 2px; }
      `}</style>
    </div>
  );
}
